patch:
--- a/adder.v
+++ b/adder.v
@@ -1,11 +1,11 @@
 module add4bit (
   input [3:0] a,
   input [3:0] b,
   output [4:0] sum
 );
   assign sum = a + b;
 endmodule

 module top;
   wire [3:0] x, y;
-  wire [3:0] result;
+  wire [4:0] result;
   add4bit inst1 (.a(x), .b(y), .sum(result));
 endmodule

before_code:
module add4bit (
  input [3:0] a,
  input [3:0] b,
  output [4:0] sum
);
  assign sum = a + b;
endmodule

module top;
  wire [3:0] x, y;
  wire [3:0] result;
  add4bit inst1 (.a(x), .b(y), .sum(result));
endmodule

after_code:
module add4bit (
  input [3:0] a,
  input [3:0] b,
  output [4:0] sum
);
  assign sum = a + b;
endmodule

module top;
  wire [3:0] x, y;
  wire [4:0] result;
  add4bit inst1 (.a(x), .b(y), .sum(result));
